1	import { useState, useEffect, useRef } from "react";
2	import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
3	import { supabase } from "@/integrations/supabase/client";
4	import type { StyleGroup } from "@/hooks/useStyleGroups";
5	import type { Asset } from "@/types/assets";
6	import { getPathDisplayModes, getUserSyncRoot, type NasConfig } from "@/lib/path-utils";
7	import { getOpenFolderUri, buildOpenFolderUri, getPreferredPathMode } from "@/lib/open-folder";
8	import { formatFilename } from "@/lib/format-filename";
9	import { format } from "date-fns";
10	import { Badge } from "@/components/ui/badge";
11	import { Button } from "@/components/ui/button";
12	import { Input } from "@/components/ui/input";
13	import { ScrollArea } from "@/components/ui/scroll-area";
14	import { Separator } from "@/components/ui/separator";
15	import {
16	  Select,
17	  SelectContent,
18	  SelectItem,
19	  SelectTrigger,
20	  SelectValue,
21	} from "@/components/ui/select";
22	import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
23	import { toast } from "sonner";
24	import {
25	  X, ImageOff, Copy, Check, Star, Loader2,
26	  ChevronLeft, ChevronRight, Sparkles, Clock,
27	  HardDrive, Tag, FileText, FolderSearch, FolderOpen, Download,
28	} from "lucide-react";
29	import {
30	  ContextMenu,
31	  ContextMenuContent,
32	  ContextMenuItem,
33	  ContextMenuSeparator,
34	  ContextMenuTrigger,
35	} from "@/components/ui/context-menu";
36	import CheckoutBar from "@/components/library/CheckoutBar";
37	import { cn } from "@/lib/utils";
38	import { Constants } from "@/integrations/supabase/types";
39	import { useAdminApi } from "@/hooks/useAdminApi";
40	
41	interface StyleGroupDetailPanelProps {
42	  group: StyleGroup;
43	  onClose: () => void;
44	}
