46	/* ── Tiny helpers ─────────────────────────────────────────── */
47	
48	function CopyInlineButton({ value, label }: { value: string; label?: string }) {
49	  const [copied, setCopied] = useState(false);
50	  const copy = async () => {
51	    await navigator.clipboard.writeText(value);
52	    setCopied(true);
53	    setTimeout(() => setCopied(false), 1500);
54	  };
55	  const btn = (
56	    <Button variant="ghost" size="icon" className="h-6 w-6 shrink-0 opacity-0 group-hover:opacity-100 transition-opacity" onClick={copy}>
57	      {copied ? <Check className="h-3 w-3 text-[hsl(var(--success))]" /> : <Copy className="h-3 w-3" />}
58	    </Button>
59	  );
60	  if (!label) return btn;
61	  return (
62	    <Tooltip>
63	      <TooltipTrigger asChild>{btn}</TooltipTrigger>
64	      <TooltipContent side="top">{copied ? "Copied!" : `Copy ${label}`}</TooltipContent>
65	    </Tooltip>
66	  );
67	}
68	
69	function CopyPathRow({ label, value }: { label: string; value: string }) {
70	  const [copied, setCopied] = useState(false);
71	  const copy = async () => {
72	    await navigator.clipboard.writeText(value);
73	    setCopied(true);
74	    setTimeout(() => setCopied(false), 1500);
75	  };
76	  return (
77	    <div className="group flex items-start gap-2">
78	      <div className="flex-1 min-w-0">
79	        <span className="text-[10px] uppercase text-muted-foreground tracking-wider">{label}</span>
80	        <p className="text-xs font-mono break-all text-foreground/80 mt-0.5">{value}</p>
81	      </div>
82	      <Button variant="ghost" size="icon" className="h-6 w-6 shrink-0 opacity-0 group-hover:opacity-100 transition-opacity" onClick={copy}>
83	        {copied ? <Check className="h-3 w-3 text-[hsl(var(--success))]" /> : <Copy className="h-3 w-3" />}
84	      </Button>
85	    </div>
86	  );
87	}
88	
89	function MetaRow({ label, value }: { label: string; value: React.ReactNode }) {
90	  if (!value || value === "—") return null;
91	  return (
92	    <div className="flex items-baseline gap-3">
93	      <span className="text-xs text-muted-foreground shrink-0 w-20">{label}</span>
94	      <span className="text-xs text-foreground overflow-x-auto whitespace-nowrap scrollbar-thin">{value ?? "—"}</span>
95	    </div>
96	  );
97	}
98	
99	function formatSize(bytes: number | null): string {
100	  if (!bytes) return "—";
101	  if (bytes < 1024) return `${bytes} B`;
102	  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(0)} KB`;
103	  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
104	}
105	
106	/** Full-screen lightbox for viewing images */
107	function Lightbox({ url, alt, onClose }: { url: string; alt: string; onClose: () => void }) {
108	  useEffect(() => {
109	    const handler = (e: KeyboardEvent) => { if (e.key === "Escape") onClose(); };
110	    window.addEventListener("keydown", handler);
111	    return () => window.removeEventListener("keydown", handler);
112	  }, [onClose]);
113	
114	  return (
115	    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80" onClick={onClose}>
116	      <img src={url} alt={alt} className="max-w-[90vw] max-h-[90vh] object-contain" onClick={(e) => e.stopPropagation()} />
117	    </div>
118	  );
119	}
