121	/* ── Find Alternative Images component ────────────────────── */
122	
123	interface SiblingImage {
124	  filename: string;
125	  relative_path: string;
126	  file_size: number;
127	  thumbnail_url?: string;
128	}
129	
130	function FindAlternativeImages({ group, onIngested }: { group: StyleGroup; onIngested?: () => void }) {
131	  const { call } = useAdminApi();
132	  const [loading, setLoading] = useState(false);
133	  const [siblings, setSiblings] = useState<SiblingImage[] | null>(null);
134	  const [error, setError] = useState<string | null>(null);
135	  const [polling, setPolling] = useState(false);
136	  const [requestId, setRequestId] = useState<string | null>(null);
137	  const [initialLoaded, setInitialLoaded] = useState(false);
138	  const [selected, setSelected] = useState<Set<string>>(new Set());
139	  const [ingesting, setIngesting] = useState(false);
140	  const pollTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);
141	  const pollCountRef = useRef(0);
142	
143	  // Cleanup polling on unmount
144	  useEffect(() => {
145	    return () => {
146	      if (pollTimerRef.current) clearInterval(pollTimerRef.current);
147	    };
148	  }, []);
149	
150	  const stopPolling = () => {
151	    if (pollTimerRef.current) {
152	      clearInterval(pollTimerRef.current);
153	      pollTimerRef.current = null;
154	    }
155	    setPolling(false);
156	    pollCountRef.current = 0;
157	  };
158	
159	  const startPolling = (reqId: string) => {
160	    if (pollTimerRef.current) clearInterval(pollTimerRef.current);
161	    pollCountRef.current = 0;
162	    setPolling(true);
163	    setRequestId(reqId);
164	
165	    pollTimerRef.current = setInterval(async () => {
166	      pollCountRef.current++;
167	      if (pollCountRef.current > 30) {
168	        stopPolling();
169	        setError("Scan timed out — the Bridge Agent may be offline. Try again later.");
170	        return;
171	      }
172	
173	      try {
174	        const result = await call("get-sibling-scan-result", { request_id: reqId });
175	        if (result?.status === "completed") {
176	          stopPolling();
177	          const images = (result.images ?? []) as SiblingImage[];
178	          setSiblings(images);
179	          setSelected(new Set());
180	          if (images.length === 0) {
181	            toast("No alternative images found", { description: "No JPG, PNG, or eligible PDF files exist in this folder on the NAS." });
182	          } else {
183	            toast(`Found ${images.length} image${images.length !== 1 ? "s" : ""}`);
184	          }
185	        } else if (result?.status === "failed") {
186	          stopPolling();
187	          const msg = result.error_message || "Scan failed";
188	          setError(msg);
189	          toast.error("Folder scan failed", { description: msg });
190	        }
191	      } catch (e) {
192	        console.warn("Poll error:", (e as Error).message);
193	      }
194	    }, 5000);
195	  };
196	
197	  // Auto-load existing results on mount
198	  useEffect(() => {
199	    if (initialLoaded || !group.folder_path) return;
200	    setInitialLoaded(true);
201	
202	    (async () => {
203	      try {
204	        const result = await call("get-sibling-scan-by-folder", { folder_path: group.folder_path });
205	        if (!result?.found) return;
206	
207	        if (result.status === "completed") {
208	          const images = (result.images ?? []) as SiblingImage[];
209	          setSiblings(images);
210	        } else if (result.status === "failed") {
211	          setError(result.error_message || "Previous scan failed");
212	        } else if (result.status === "pending") {
213	          startPolling(result.request_id as string);
214	        }
215	      } catch {
216	        // Non-fatal
217	      }
218	    })();
219	  }, [group.folder_path]); // eslint-disable-line react-hooks/exhaustive-deps
220	
221	  const handleFind = async () => {
222	    setLoading(true);
223	    setError(null);
224	    setSiblings(null);
225	    setSelected(new Set());
226	    stopPolling();
227	    try {
228	      const result = await call("list-sibling-images", {
229	        folder_path: group.folder_path,
230	        style_group_id: group.id,
231	      });
232	      if (result?.status === "completed") {
233	        const images = (result.images ?? []) as SiblingImage[];
234	        setSiblings(images);
235	        if (images.length === 0) {
236	          toast("No alternative images found", { description: "No JPG, PNG, or eligible PDF files exist in this folder on the NAS." });
237	        }
238	      } else if (result?.status === "failed") {
239	        setError(result.error_message || "Scan failed");
240	      } else if (result?.status === "pending") {
241	        toast("Scan requested", { description: "The Bridge Agent will scan this folder shortly. Waiting for results…" });
242	        startPolling(result.request_id as string);
243	      }
244	    } catch (e) {
245	      const msg = (e as Error).message;
246	      setError(msg);
247	      toast.error("Failed to scan folder", { description: msg });
248	    } finally {
249	      setLoading(false);
250	    }
251	  };
252	
253	  const toggleSelect = (path: string) => {
254	    setSelected(prev => {
255	      const next = new Set(prev);
256	      if (next.has(path)) next.delete(path);
257	      else next.add(path);
258	      return next;
259	    });
260	  };
261	
262	  const toggleAll = () => {
263	    if (!siblings) return;
264	    if (selected.size === siblings.length) {
265	      setSelected(new Set());
266	    } else {
267	      setSelected(new Set(siblings.map(s => s.relative_path)));
268	    }
269	  };
270	
271	  const handleIngest = async () => {
272	    if (!siblings || selected.size === 0) return;
273	    setIngesting(true);
274	    try {
275	      const selectedImages = siblings.filter(s => selected.has(s.relative_path));
276	      const result = await call("ingest-sibling-images", {
277	        style_group_id: group.id,
278	        images: selectedImages,
279	      });
280	      const summary = result?.summary as { created: number; linked: number; errors: number } | undefined;
281	      if (summary) {
282	        const parts: string[] = [];
283	        if (summary.created > 0) parts.push(`${summary.created} added`);
284	        if (summary.linked > 0) parts.push(`${summary.linked} linked`);
285	        if (summary.errors > 0) parts.push(`${summary.errors} failed`);
286	        toast("Images ingested", { description: parts.join(", ") });
287	      } else {
288	        toast("Images ingested");
289	      }
290	      // Remove ingested images from the list
291	      setSiblings(prev => prev?.filter(s => !selected.has(s.relative_path)) ?? null);
292	      setSelected(new Set());
293	      onIngested?.();
294	    } catch (e) {
295	      toast.error("Ingestion failed", { description: (e as Error).message });
296	    } finally {
297	      setIngesting(false);
298	    }
299	  };
300	
301	  return (
302	    <section className="space-y-2.5">
303	      <h4 className="flex items-center gap-1.5 text-xs font-medium uppercase tracking-wider text-muted-foreground">
304	        <FolderSearch className="h-3.5 w-3.5" /> Alternative Images
305	      </h4>
306	      <p className="text-[10px] text-muted-foreground leading-relaxed">
307	        If this group lacks a proper product image, scan the NAS folder for sibling JPG, PNG, or eligible PDF files that could be used instead.
308	      </p>
309	      <Button
310	        variant="outline"
311	        size="sm"
312	        className="gap-1.5 text-xs h-7"
313	        onClick={handleFind}
314	        disabled={loading || polling}
315	        title={loading ? "Scanning folder…" : polling ? "Waiting for agent response…" : undefined}
316	      >
317	        {loading || polling ? <Loader2 className="h-3 w-3 animate-spin" /> : <FolderSearch className="h-3 w-3" />}
318	        {loading ? "Scanning…" : polling ? "Waiting for results…" : siblings ? "Re-scan Folder" : "Find Sibling Files"}
319	      </Button>
320	
321	      {error && (
322	        <p className="text-[10px] text-destructive">{error}</p>
323	      )}
324	
325	      {siblings && siblings.length > 0 && (
326	        <div className="space-y-2 rounded-md border border-border p-2 bg-muted/20">
327	          <div className="flex items-center justify-between">
328	            <p className="text-[10px] text-muted-foreground font-medium">
329	              Found {siblings.length} image{siblings.length !== 1 ? "s" : ""}:
330	            </p>
331	            <div className="flex items-center gap-2">
332	              <Button variant="ghost" size="sm" className="h-5 text-[10px] px-1.5" onClick={toggleAll}>
333	                {selected.size === siblings.length ? "Deselect All" : "Select All"}
334	              </Button>
335	            </div>
336	          </div>
337	          <div className="grid grid-cols-2 gap-2">
338	            {siblings.map((img) => {
339	              const isSelected = selected.has(img.relative_path);
340	              return (
341	                <div
342	                  key={img.relative_path}
343	                  className={cn(
344	                    "rounded-md border overflow-hidden bg-background cursor-pointer transition-colors",
345	                    isSelected ? "border-primary ring-1 ring-primary/30" : "border-border/50 hover:border-border"
346	                  )}
347	                  onClick={() => toggleSelect(img.relative_path)}
348	                >
349	                  {img.thumbnail_url ? (
350	                    <div className="aspect-square w-full bg-muted/30 overflow-hidden relative">
351	                      <img
352	                        src={img.thumbnail_url}
353	                        alt={img.filename}
354	                        className="h-full w-full object-contain"
355	                        loading="lazy"
356	                      />
357	                      {isSelected && (
358	                        <div className="absolute top-1 right-1 h-5 w-5 rounded-full bg-primary flex items-center justify-center">
359	                          <Check className="h-3 w-3 text-primary-foreground" />
360	                        </div>
361	                      )}
362	                    </div>
363	                  ) : (
364	                    <div className="aspect-square w-full bg-muted/30 flex items-center justify-center relative">
365	                      <ImageOff className="h-6 w-6 text-muted-foreground/20" />
366	                      {isSelected && (
367	                        <div className="absolute top-1 right-1 h-5 w-5 rounded-full bg-primary flex items-center justify-center">
368	                          <Check className="h-3 w-3 text-primary-foreground" />
369	                        </div>
370	                      )}
371	                    </div>
372	                  )}
373	                  <div className="p-1.5 space-y-0.5">
374	                    <p className="font-mono text-[10px] truncate" title={img.relative_path}>
375	                      {img.filename}
376	                    </p>
377	                    <p className="text-[9px] text-muted-foreground">
378	                      {img.file_size ? `${(img.file_size / 1024).toFixed(0)} KB` : ""}
379	                    </p>
380	                  </div>
381	                </div>
382	              );
383	            })}
384	          </div>
385	          {selected.size > 0 && (
386	            <Button
387	              size="sm"
388	              className="w-full gap-1.5 text-xs h-7"
389	              onClick={handleIngest}
390	              disabled={ingesting}
391	              title={ingesting ? "Adding images to group, please wait…" : undefined}
392	            >
393	              {ingesting ? <Loader2 className="h-3 w-3 animate-spin" /> : <Check className="h-3 w-3" />}
394	              Add {selected.size} Image{selected.size !== 1 ? "s" : ""} to Group
395	            </Button>
396	          )}
397	        </div>
398	      )}
399	
400	      {polling && (
401	        <div className="rounded-md border border-[hsl(var(--warning)/0.3)] bg-[hsl(var(--warning)/0.05)] p-2.5 space-y-1">
402	          <p className="text-[10px] text-[hsl(var(--warning))] font-medium flex items-center gap-1">
403	            <Loader2 className="h-3 w-3 animate-spin" /> Waiting for Bridge Agent…
404	          </p>
405	          <p className="text-[10px] text-muted-foreground leading-relaxed">
406	            The Bridge Agent is scanning folder <span className="font-mono">{group.folder_path}</span> for sibling JPG, PNG, and eligible PDF files. This typically takes 10–30 seconds.
407	          </p>
408	        </div>
409	      )}
410	
411	      {siblings && siblings.length === 0 && !polling && (
412	        <p className="text-[10px] text-muted-foreground/60">No sibling files found in this folder.</p>
413	      )}
414	    </section>
415	  );
416	}
