418	/* ── Main component ───────────────────────────────────────── */
419	
420	export default function StyleGroupDetailPanel({ group, onClose }: StyleGroupDetailPanelProps) {
421	  const queryClient = useQueryClient();
422	  const { call: adminApi } = useAdminApi();
423	  const [localPrimaryId, setLocalPrimaryId] = useState<string | null>(group.primary_asset_id);
424	
425	  // Keep localPrimaryId in sync when the group prop changes (e.g. after rebuild/refetch)
426	  useEffect(() => {
427	    setLocalPrimaryId(group.primary_asset_id);
428	  }, [group.primary_asset_id]);
429	  const [selectedAssetId, setSelectedAssetId] = useState<string | null>(null);
430	  const [carouselIndex, setCarouselIndex] = useState(0);
431	  const [lightboxUrl, setLightboxUrl] = useState<string | null>(null);
432	  const [tagInput, setTagInput] = useState("");
433	  const [aiTagging, setAiTagging] = useState(false);
434	  const [syncingTags, setSyncingTags] = useState(false);
435	
436	  const ERP_MG_CUTOFF = "2025-05-14";
437	
438	  // Fetch ERP item data for this group's SKU (legacy check + description)
439	  const { data: erpItemData } = useQuery({
440	    queryKey: ["erp-item-data", group.sku],
441	    queryFn: async () => {
442	      const { data } = await supabase
443	        .from("erp_items_current")
444	        .select("erp_updated_at, item_description")
445	        .eq("style_number", group.sku)
446	        .limit(1)
447	        .maybeSingle();
448	      return data ?? null;
449	    },
450	    staleTime: 5 * 60 * 1000,
451	  });
452	
453	  const isLegacyGroup = erpItemData?.erp_updated_at ? erpItemData.erp_updated_at < ERP_MG_CUTOFF : false;
454	  const erpDescription = erpItemData?.item_description ?? null;
455	
456	  // Fetch all assets in this group
457	  const { data: groupAssets, isLoading: assetsLoading } = useQuery({
458	    queryKey: ["style-group-assets", group.id],
459	    queryFn: async () => {
460	      const { data, error } = await supabase
461	        .from("assets")
462	        .select("*")
463	        .eq("style_group_id", group.id)
464	        .eq("is_deleted", false)
465	        .order("filename");
466	      if (error) throw error;
467	      return (data ?? []) as Asset[];
468	    },
469	  });
470	
471	  // NAS config for path display
472	  const { data: nasConfig } = useQuery({
473	    queryKey: ["nas-config"],
474	    queryFn: async () => {
475	      const { data } = await supabase
476	        .from("admin_config")
477	        .select("key, value")
478	        .in("key", ["NAS_HOST", "NAS_IP", "NAS_SHARE"]);
479	      const map: Record<string, string> = {};
480	      for (const row of data ?? []) map[row.key] = typeof row.value === "string" ? row.value : String(row.value);
481	      return {
482	        NAS_HOST: map.NAS_HOST ?? "nas",
483	        NAS_IP: map.NAS_IP ?? "0.0.0.0",
484	        NAS_SHARE: map.NAS_SHARE ?? "share",
485	      } as NasConfig;
486	    },
487	    staleTime: 5 * 60 * 1000,
488	  });
489	
490	  // Style guide source files for licensed groups
491	  const { data: styleGuideSources } = useQuery({
492	    queryKey: ["sku-files-used", group.sku],
493	    enabled: !!group.sku && group.is_licensed,
494	    queryFn: async () => {
495	      const { data } = await supabase
496	        .from("sku_files_used")
497	        .select("id, file_name, style_guide_file_id, style_guide_files(filename, licensor_name, property_folder)")
498	        .eq("sku", group.sku)
499	        .order("file_name");
500	      return (data ?? []) as Array<{
501	        id: string;
502	        file_name: string;
503	        style_guide_file_id: string | null;
504	        style_guide_files: { filename: string; licensor_name: string | null; property_folder: string | null } | null;
505	      }>;
506	    },
507	    staleTime: 2 * 60 * 1000,
508	  });
509	
510	  // Thumbnailed assets for the carousel
511	  const thumbStrip = (groupAssets ?? []).filter((a) => !!a.thumbnail_url);
512	
513	  // Keep carouselIndex in bounds
514	  useEffect(() => {
515	    if (thumbStrip.length > 0 && carouselIndex >= thumbStrip.length) {
516	      setCarouselIndex(thumbStrip.length - 1);
517	    }
518	  }, [thumbStrip.length, carouselIndex]);
519	
520	  // When selectedAssetId changes, sync carouselIndex
521	  useEffect(() => {
522	    if (!selectedAssetId) return;
523	    const idx = thumbStrip.findIndex((a) => a.id === selectedAssetId);
524	    if (idx >= 0) setCarouselIndex(idx);
525	  }, [selectedAssetId, thumbStrip]);
526	
527	  // Current asset from carousel
528	  const currentThumbAsset = thumbStrip[carouselIndex] ?? null;
529	  const displayThumbnail = currentThumbAsset?.thumbnail_url ?? group.thumbnail_url;
530	
531	  // The asset to show detail for — prefer carousel asset, fallback to first asset
532	  const detailAsset = currentThumbAsset ?? groupAssets?.[0] ?? null;
533	
534	  // Path display
535	  const paths = nasConfig && detailAsset
536	    ? getPathDisplayModes(detailAsset.relative_path, nasConfig, getUserSyncRoot())
537	    : null;
538	
539	  // Set cover mutation
540	  const setCover = useMutation({
541	    mutationFn: async (assetId: string) => {
542	      const { error } = await supabase.rpc("set_style_group_cover", {
543	        p_group_id: group.id,
544	        p_asset_id: assetId,
545	      });
546	      if (error) throw error;
547	    },
548	    onSuccess: (_data, assetId) => {
549	      setLocalPrimaryId(assetId);
550	      queryClient.invalidateQueries({ queryKey: ["style-groups"] });
551	      queryClient.invalidateQueries({ queryKey: ["style-group-assets", group.id] });
552	      toast("Cover image updated");
