582	      const opKey = `ai-tag-single-${detailAsset.id}`;
583	      const now = new Date().toISOString();
584	      const { error } = await supabase.rpc("update_bulk_operation", {
585	        p_op_key: opKey,
586	        p_op_state: {
587	          status: "running",
588	          cursor: 0,
589	          params: { type: "bulk-ai-tag-all", asset_ids: [detailAsset.id], total: 1 },
590	          started_at: now,
591	          updated_at: now,
592	          progress: { tagged: 0, skipped: 0, failed: 0, total: 1 },
593	        },
594	      });
595	      if (error) throw error;
596	
597	      // Poll for completion (worker picks it up within ~5s)
598	      const maxWaitMs = 90_000;
599	      const pollMs = 2_000;
600	      const start = Date.now();
601	      while (Date.now() - start < maxWaitMs) {
602	        await new Promise((r) => setTimeout(r, pollMs));
603	        const { data: configRow } = await supabase
604	          .from("admin_config")
605	          .select("value")
606	          .eq("key", "BULK_OPERATIONS")
607	          .maybeSingle();
608	        const ops = configRow?.value as Record<string, any> | undefined;
609	        const op = ops?.[opKey];
610	        if (!op || op.status === "completed") {
611	          try { await supabase.rpc("update_bulk_operation", {
612	            p_op_key: opKey,
613	            p_op_state: { status: "idle" },
614	          }); } catch { /* best-effort cleanup */ }
615	          queryClient.invalidateQueries({ queryKey: ["style-group-assets", group.id] });
616	          toast("AI tagging complete");
617	          return;
618	        }
619	        if (op.status === "failed" || op.status === "interrupted") {
620	          throw new Error(op.error || "AI tagging failed");
621	        }
622	      }
623	      toast("AI tagging is still running — check back shortly");
624	    } catch (e: any) {
625	      toast.error("AI tagging failed", { description: e.message });
626	    } finally {
