2	CREATE TABLE sku_files_used (
3	  id         uuid PRIMARY KEY DEFAULT gen_random_uuid(),
4	  sku        text NOT NULL,
5	  file_name  text NOT NULL,
6	  created_at timestamptz NOT NULL DEFAULT now(),
7	  UNIQUE (sku, file_name)
8	);
9	CREATE INDEX ON sku_files_used (sku);
10	
11	-- RLS
12	ALTER TABLE sku_files_used ENABLE ROW LEVEL SECURITY;
13	CREATE POLICY "authenticated read" ON sku_files_used
14	  FOR SELECT TO authenticated USING (true);
15	CREATE POLICY "service role all" ON sku_files_used
16	  TO service_role USING (true) WITH CHECK (true);
17	
18	-- Per-asset parsing function
19	CREATE OR REPLACE FUNCTION parse_pdf_files_used(p_asset_id uuid)
20	RETURNS int LANGUAGE plpgsql AS $$
21	DECLARE
22	  v_sku     text;
23	  v_text    text;
24	  v_lines   text[];
25	  v_in_sect boolean := false;
26	  v_line    text;
27	  v_trimmed text;
28	  v_count   int := 0;
29	BEGIN
30	  SELECT sku INTO v_sku FROM assets WHERE id = p_asset_id;
31	  IF v_sku IS NULL OR v_sku = '' THEN RETURN 0; END IF;
32	
33	  SELECT extracted_text INTO v_text
34	  FROM pdf_text_samples
35	  WHERE asset_id = p_asset_id AND extracted_text IS NOT NULL
36	  ORDER BY sampled_at DESC LIMIT 1;
37	  IF v_text IS NULL THEN RETURN 0; END IF;
38	
39	  v_lines := string_to_array(v_text, E'\n');
40	  FOREACH v_line IN ARRAY v_lines LOOP
41	    v_trimmed := trim(v_line);
42	
43	    -- Detect "Files Used", "Source Files", "Art Files", "Design Files" section headers
44	    IF v_trimmed ~* '^\s*(files?\s+used|source\s+files?|art\s+files?|design\s+files?)\s*:?\s*$' THEN
45	      v_in_sect := true;
46	      CONTINUE;
47	    END IF;
48	
49	    IF v_in_sect THEN
50	      -- Stop at blank line or a new section header (text ending with colon)
51	      IF v_trimmed = '' OR v_trimmed ~ '^\S[^:]*:\s*$' THEN
52	        v_in_sect := false;
53	        CONTINUE;
54	      END IF;
55	      -- Skip pure numbers (page numbers) or single-char tokens
56	      IF v_trimmed ~ '^\d+$' OR length(v_trimmed) < 2 THEN CONTINUE; END IF;
57	
58	      INSERT INTO sku_files_used (sku, file_name)
59	      VALUES (v_sku, v_trimmed)
60	      ON CONFLICT (sku, file_name) DO NOTHING;
61	      v_count := v_count + 1;
62	    END IF;
63	  END LOOP;
64	  RETURN v_count;
65	END;
66	$$;
67	
68	-- Backfill function: process all existing assets with text samples
69	CREATE OR REPLACE FUNCTION backfill_pdf_files_used()
70	RETURNS int LANGUAGE plpgsql AS $$
71	DECLARE
72	  v_id    uuid;
73	  v_total int := 0;
74	BEGIN
75	  FOR v_id IN (
76	    SELECT DISTINCT asset_id
77	    FROM pdf_text_samples
78	    WHERE asset_id IS NOT NULL
79	      AND extracted_text IS NOT NULL
80	      AND char_count > 100
81	  ) LOOP
82	    v_total := v_total + parse_pdf_files_used(v_id);
83	  END LOOP;
84	  RETURN v_total;
85	END;
86	$$;
87	
88	-- Auto-trigger: parse whenever a new pdf_text_samples row is inserted
89	CREATE OR REPLACE FUNCTION trg_fn_parse_pdf_files_used()
90	RETURNS trigger LANGUAGE plpgsql AS $$
91	BEGIN
92	  IF NEW.asset_id IS NOT NULL AND NEW.extracted_text IS NOT NULL THEN
93	    PERFORM parse_pdf_files_used(NEW.asset_id);
94	  END IF;
95	  RETURN NEW;
96	END;
97	$$;
98	
99	CREATE TRIGGER trg_pdf_text_samples_parse_files
100	AFTER INSERT ON pdf_text_samples
101	FOR EACH ROW EXECUTE FUNCTION trg_fn_parse_pdf_files_used();
