3003	  if (results.length === 0) return json({ ok: true, remaining: 0 });
3004	
3005	  let filesUsedAdded = 0;
3006	
3007	  // 1. Insert into pdf_text_samples (skip assets already there)
3008	  const sampleRows = results.map((r) => ({
3009	    asset_id: (r.asset_id as string) || null,
3010	    filename: r.filename as string,
3011	    relative_path: r.relative_path as string,
3012	    extraction_method: r.extraction_method as string,
3013	    extracted_text: (r.extracted_text as string) || null,
3014	    page_count: (r.page_count as number) || null,
3015	    char_count: (r.char_count as number) || 0,
3016	    extraction_error: (r.extraction_error as string) || null,
3017	    thumbnail_url: (r.sample_thumbnail_url as string) || null,
3018	    sampled_at: new Date().toISOString(),
3019	  }));
3020	  await db.from("pdf_text_samples").upsert(sampleRows, { onConflict: "asset_id", ignoreDuplicates: true });
3021	
3022	  // 2. Parse FILES USED sections and insert to sku_files_used
3023	  const resultsWithText = results.filter((r) => r.extracted_text && r.asset_id);
3024	  if (resultsWithText.length > 0) {
3025	    const { data: skuRows } = await db.from("assets")
3026	      .select("id, sku")
3027	      .in("id", resultsWithText.map((r) => r.asset_id as string))
3028	      .not("sku", "is", null)
3029	      .neq("sku", "");
3030	
3031	    const skuMap = new Map((skuRows || []).map((r: { id: string; sku: string }) => [r.id, r.sku]));
3032	
3033	    const filesUsedRows: { sku: string; file_name: string }[] = [];
3034	    for (const r of resultsWithText) {
3035	      const sku = skuMap.get(r.asset_id as string);
3036	      if (!sku) continue;
