3038	      for (const fn of fileNames) {
3039	        filesUsedRows.push({ sku, file_name: fn });
3040	      }
3041	    }
3042	
3043	    if (filesUsedRows.length > 0) {
3044	      // ignoreDuplicates → returned rows are only the newly-inserted ones, so .select()
3045	      // gives an accurate count of files-used actually added (for the UI summary).
3046	      const { data: inserted } = await db.from("sku_files_used")
3047	        .upsert(filesUsedRows, { onConflict: "sku,file_name", ignoreDuplicates: true })
3048	        .select("sku");
3049	      filesUsedAdded = (inserted as unknown[] | null)?.length ?? 0;
3050	    }
3051	  }
3052	
3053	  // 3. Update assets.thumbnail_url where currently NULL
3054	  const thumbnailUpdates = results.filter((r) => r.asset_thumbnail_url && r.asset_id);
3055	  for (const r of thumbnailUpdates) {
3056	    await db.from("assets")
3057	      .update({ thumbnail_url: r.asset_thumbnail_url as string, thumbnail_error: null })
3058	      .eq("id", r.asset_id as string)
3059	      .is("thumbnail_url", null);
3060	  }
3061	
3062	  // 4. Increment processed count in admin_config
3063	  const { data: bfRow } = await db.from("admin_config")
3064	    .select("value").eq("key", "PDF_BACKFILL").maybeSingle();
3065	  const bf = (bfRow?.value as Record<string, unknown>) || {};
3066	  const newProcessed = ((bf.processed as number) ?? 0) + results.length;
3067	  const total = (bf.total as number) ?? 0;
3068	  const nowIso = new Date().toISOString();
3069	
3070	  // Accumulate per-method outcome tallies + files-used added for the UI summary.
3071	  const stats: Record<string, number> = { ...((bf.stats as Record<string, number>) ?? {}) };
3072	  for (const r of results) {
3073	    const method = (r.extraction_method as string) || "unknown";
3074	    stats[method] = (stats[method] ?? 0) + 1;
3075	  }
3076	
3077	  const newBf: Record<string, unknown> = {
3078	    ...bf,
3079	    processed: newProcessed,
3080	    last_batch_at: nowIso,
3081	    stats,
3082	    files_used_added: ((bf.files_used_added as number) ?? 0) + filesUsedAdded,
